arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator" — keep it so they remain queryable
        // and direct SQL queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to just "123".
        // Existing documents use the compound format — keep it so FindAsync
        // and point-reads resolve correctly against existing data.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // HasIndex removed: EF Core 9 Cosmos provider throws at startup for HasIndex.
    // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal/Bicep/Terraform).
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" (not "$type")
        // via HasDiscriminator<string>("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports sync I/O.
        // ToList() throws; use ToListAsync() instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

